<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use Illuminate\Http\Request;use Illuminate\Support\Str;
abstract class SimpleResourceController extends Controller{use HandlesAdminUploads;protected string $model;protected string $route;protected string $title;protected array $fields=[];protected array $rules=[];protected array $bools=[];protected array $files=[];public function index(){return view('admin.crud.index',['title'=>$this->title,'items'=>($this->model)::latest()->paginate(20),'route'=>$this->route,'columns'=>['title'=>'عنوان','name'=>'نام','key'=>'کلید','position'=>'جایگاه','is_active'=>'وضعیت']]);}public function create(){return view('admin.crud.form',['title'=>$this->title,'item'=>new $this->model,'route'=>$this->route,'fields'=>$this->fields]);}public function store(Request $r){$d=$r->validate($this->rules);if(isset($d['slug'])&&empty($d['slug']))$d['slug']=Str::slug($d['title']??$d['name']);foreach($this->bools as $b)$d[$b]=$r->boolean($b);foreach($this->files as $f=>$dir)$d[$f]=$this->upload($r,$f,$dir);($this->model)::create($d);return redirect()->route('admin.'.$this->route.'.index')->with('success','ذخیره شد');}public function edit($id){$item=($this->model)::findOrFail($id);return view('admin.crud.form',['title'=>$this->title,'item'=>$item,'route'=>$this->route,'fields'=>$this->fields]);}public function update(Request $r,$id){$item=($this->model)::findOrFail($id);$rules=$this->rules;foreach(['slug','key'] as $u)if(isset($rules[$u]))$rules[$u]=preg_replace('/unique:[^|]+/','unique:'.$item->getTable().','.$u.','.$item->id,$rules[$u]);$d=$r->validate($rules);foreach($this->bools as $b)$d[$b]=$r->boolean($b);foreach($this->files as $f=>$dir)$d[$f]=$this->upload($r,$f,$dir,$item->$f);$item->update($d);return redirect()->route('admin.'.$this->route.'.index')->with('success','به‌روزرسانی شد');}public function destroy($id){($this->model)::findOrFail($id)->delete();return back();}}
